import{_ as e,o as l,c as i,aA as r}from"./chunks/framework.CAIZw9CR.js";const h=JSON.parse('{"title":"Capabilities matrix","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities.md","filePath":"capabilities.md","lastUpdated":null}'),a={name:"capabilities.md"};function n(d,t,s,o,g,c){return l(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="Capabilities-matrix" tabindex="-1">Capabilities matrix <a class="header-anchor" href="#Capabilities-matrix" aria-label="Permalink to &quot;Capabilities matrix {#Capabilities-matrix}&quot;">​</a></h1><p>This page is the single-source-of-truth for <strong>what Kraken.jl can do today</strong>, what is partially implemented, and what is out of scope for v0.1.0. Every entry links to the theory page that derives it, the example that exercises it, and the API or .krk reference that documents how to call it.</p><p>If a row says <strong>in v0.1.0</strong> it is part of the shipped feature set. Rows marked <strong>code present, v0.2.0</strong> exist in the codebase (and in some cases are fully tested) but are deliberately excluded from the v0.1.0 publication scope — they will be documented and validated in a later release.</p><p>Legend: ✓ = works and tested · ~ = implemented, partial validation · — = not applicable · ✗ = not yet</p><hr><h2 id="1.-Core-LBM" tabindex="-1">1. Core LBM <a class="header-anchor" href="#1.-Core-LBM" aria-label="Permalink to &quot;1. Core LBM {#1.-Core-LBM}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">2D</th><th style="text-align:center;">3D</th><th style="text-align:center;">GPU</th><th style="text-align:center;">.krk</th><th style="text-align:center;">Theory</th><th style="text-align:center;">Example</th><th style="text-align:center;">API</th></tr></thead><tbody><tr><td style="text-align:right;">D2Q9 / D3Q19 lattice</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><a href="./theory/01_lbm_fundamentals">01</a>, <a href="./theory/02_d2q9_lattice">02</a>, <a href="./theory/06_from_2d_to_3d">06</a></td><td style="text-align:center;"><a href="./examples/01_poiseuille_2d">Poiseuille 2D</a>, <a href="./examples/05_cavity_3d">Cavity 3D</a></td><td style="text-align:center;"><a href="./api/lattice">lattice</a></td></tr><tr><td style="text-align:right;">BGK collision</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><a href="./theory/03_bgk_collision">03</a></td><td style="text-align:center;"><a href="./examples/04_cavity_2d">Cavity 2D</a></td><td style="text-align:center;"><a href="./api/collision">collision</a></td></tr><tr><td style="text-align:right;">MRT collision</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><a href="./theory/12_mrt">12</a></td><td style="text-align:center;">—</td><td style="text-align:center;"><a href="./api/collision">collision</a></td></tr><tr><td style="text-align:right;">Streaming (periodic/wall)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><a href="./theory/04_streaming">04</a></td><td style="text-align:center;"><a href="./examples/02_couette_2d">Couette</a></td><td style="text-align:center;"><a href="./api/streaming">streaming</a></td></tr><tr><td style="text-align:right;">Macroscopic recovery (ρ, u)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;"><a href="./theory/01_lbm_fundamentals">01</a></td><td style="text-align:center;">—</td><td style="text-align:center;"><a href="./api/macroscopic">macroscopic</a></td></tr><tr><td style="text-align:right;">Body force (Guo forcing)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><a href="./theory/07_body_forces">07</a></td><td style="text-align:center;"><a href="./examples/01_poiseuille_2d">Poiseuille 2D</a></td><td style="text-align:center;"><a href="./api/collision">collision</a></td></tr><tr><td style="text-align:right;">Axisymmetric (z, r)</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><a href="./theory/09_axisymmetric">09</a></td><td style="text-align:center;"><a href="./examples/09_hagen_poiseuille">Hagen–Poiseuille</a></td><td style="text-align:center;"><a href="./api/drivers">drivers</a></td></tr></tbody></table><p><strong>Limitations:</strong> MRT is D2Q9 only in v0.1.0. D3Q27 not implemented.</p><h2 id="2.-Boundary-conditions" tabindex="-1">2. Boundary conditions <a class="header-anchor" href="#2.-Boundary-conditions" aria-label="Permalink to &quot;2. Boundary conditions {#2.-Boundary-conditions}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">BC type</th><th style="text-align:center;">2D</th><th style="text-align:center;">3D</th><th style="text-align:center;">Spatial f(x,y,z)</th><th style="text-align:center;">Time f(t)</th><th style="text-align:right;">.krk syntax</th></tr></thead><tbody><tr><td style="text-align:right;">Wall (bounce-back)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:right;"><code>Boundary north wall</code></td></tr><tr><td style="text-align:right;">Velocity (Zou-He)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Boundary west velocity(ux=4*U*y*(H-y)/H^2)</code></td></tr><tr><td style="text-align:right;">Pressure/density outlet</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">~</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Boundary east pressure(rho=1.0)</code></td></tr><tr><td style="text-align:right;">Periodic</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:right;"><code>Boundary x periodic</code></td></tr><tr><td style="text-align:right;">Fixed temperature (Dirichlet)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td><td style="text-align:right;"><code>Boundary west wall(T=1.0)</code></td></tr><tr><td style="text-align:right;">Adiabatic (zero-flux)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:right;">default when no <code>T=</code> specified</td></tr><tr><td style="text-align:right;">Outflow / Neumann / symmetry</td><td style="text-align:center;">~</td><td style="text-align:center;">~</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:right;">recognized, partial</td></tr></tbody></table><ul><li><p>Theory: <a href="./theory/05_boundary_conditions">05 BCs</a>, <a href="./theory/19_spatial_bcs">19 spatial BCs</a></p></li><li><p>.krk: <a href="./krk/bc_types">BC types</a>, <a href="./krk/expressions">Expressions</a></p></li><li><p>Expression whitelist: arithmetic, <code>sin/cos/tan/exp/log/sqrt/abs/clamp</code>, variables <code>x, y, z, t, Lx, Ly, Lz, Nx, Ny, Nz, dx, dy, dz</code> + <code>Define</code>d vars.</p></li></ul><p><strong>Limitations:</strong> thermal BCs are scalar only in v0.1.0 (no <code>T = f(x,y,t)</code>). Outflow/Neumann/symmetry are recognized by the parser but kernels are minimal — use with caution.</p><h2 id="3.-Thermal" tabindex="-1">3. Thermal <a class="header-anchor" href="#3.-Thermal" aria-label="Permalink to &quot;3. Thermal {#3.-Thermal}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">2D</th><th style="text-align:center;">3D</th><th style="text-align:center;">Refined</th><th style="text-align:center;">GPU</th><th style="text-align:center;">.krk</th><th style="text-align:right;">Theory / Example</th></tr></thead><tbody><tr><td style="text-align:right;">Passive scalar transport (DDF)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><code>Module thermal</code></td><td style="text-align:right;"><a href="./theory/08_thermal_ddf">08 thermal DDF</a></td></tr><tr><td style="text-align:right;">Boussinesq buoyancy</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">auto when hot/cold BCs set</td><td style="text-align:right;"><a href="./examples/08_rayleigh_benard">Rayleigh-Bénard</a></td></tr><tr><td style="text-align:right;">Heat conduction (pure)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./examples/07_heat_conduction">Heat conduction</a></td></tr><tr><td style="text-align:right;">Natural convection (cavity)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:right;">driver <code>run_natural_convection_2d/3d</code></td></tr><tr><td style="text-align:right;">ν(T) Arrhenius (kernel)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:right;">code: <code>collide_boussinesq_vt_2d!</code></td></tr><tr><td style="text-align:right;">ν(T) modified Arrhenius (Rc)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:right;">driver via <code>Rc</code> keyword</td></tr><tr><td style="text-align:right;">α(T), κ(T) variable diffusivity</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">✗</td><td style="text-align:right;">v0.2.0</td></tr><tr><td style="text-align:right;">Validation vs De Vahl Davis (Ra=1e3)</td><td style="text-align:center;">✓ 1.4%</td><td style="text-align:center;">—</td><td style="text-align:center;">✓ 1.4%</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:right;">Nu = 1.118 ref</td></tr><tr><td style="text-align:right;">Validation vs Fusegi (3D Ra=1e3)</td><td style="text-align:center;">—</td><td style="text-align:center;">~ 5%</td><td style="text-align:center;">pending AQUA</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:right;">Nu = 1.085 ref</td></tr></tbody></table><p><strong>Limitations in v0.1.0:</strong></p><ul><li><p>ν(T) is wired at the <strong>driver</strong> level (<code>run_natural_convection_2d(; Rc=5)</code>) but <strong>not yet dispatched from .krk</strong>. Adding <code>Rc = 5</code> in <code>Physics {}</code> does not activate the variable-viscosity kernel. Workaround: call the Julia API directly. Fix planned for v0.2.0.</p></li><li><p>No custom <code>ν(x, y, z, t, γ̇, T)</code> user-defined function inlined into kernels — this requires a parser extension (planned v0.2.0).</p></li><li><p>Thermal BCs are scalar only; <code>T = sin(π*y)*t/T_max</code> is not supported yet.</p></li></ul><h2 id="4.-Grid-refinement" tabindex="-1">4. Grid refinement <a class="header-anchor" href="#4.-Grid-refinement" aria-label="Permalink to &quot;4. Grid refinement {#4.-Grid-refinement}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">2D</th><th style="text-align:center;">3D</th><th style="text-align:center;">Thermal</th><th style="text-align:center;">GPU</th><th style="text-align:center;">.krk</th><th style="text-align:right;">Theory / API</th></tr></thead><tbody><tr><td style="text-align:right;">Filippova–Hanel patch-based refinement</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;"><code>Refine name { region, ratio }</code></td><td style="text-align:right;"><a href="./theory/18_grid_refinement">18 grid refinement</a></td></tr><tr><td style="text-align:right;">Temporal sub-cycling (ratio 2, 4, …)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">auto</td><td style="text-align:right;"><a href="./api/refinement">refinement</a></td></tr><tr><td style="text-align:right;">Ghost-layer bilinear/trilinear prolongation</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:right;"><a href="./api/refinement">refinement</a></td></tr><tr><td style="text-align:right;">Block-average restriction (ratio²/ratio³)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:right;"><a href="./api/refinement">refinement</a></td></tr><tr><td style="text-align:right;">Automatic τ rescaling on fine grid</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:right;">sanity check reports τ_fine</td></tr><tr><td style="text-align:right;">Full-domain wall patches</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗ (natconv)</td><td style="text-align:center;">✓ (conduction)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:right;">3D natconv unstable, see note</td></tr><tr><td style="text-align:right;">Cost-vs-accuracy win on integrated quantities (Nu, Cd)</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td><td style="text-align:center;">✗</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:right;">See <a href="./benchmarks/refinement_showcase">refinement showcase</a> — v0.2.0</td></tr><tr><td style="text-align:right;">Unified .krk dispatch (no driver)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/directives">Refine block</a></td></tr><tr><td style="text-align:right;">Multi-level (patch inside patch)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">~</td><td style="text-align:center;">~</td><td style="text-align:center;">✓</td><td style="text-align:right;">parser supports, partially tested</td></tr><tr><td style="text-align:right;">Geometry on fine patches</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">—</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>_apply_patch_geometry!</code></td></tr></tbody></table><p><strong>Key design:</strong> refinement has <strong>no dedicated driver</strong>. A <code>Refine {}</code> block in any .krk file routes automatically to <code>_run_refined</code> (2D) or <code>_run_refined_3d</code> (3D), which in turn dispatch the thermal branch when <code>Module thermal</code> is active.</p><p><strong>Limitations (3D natconv refined — known issue):</strong></p><p>AQUA H100 validation (2026-04-14, Ra=1e3, N=24 and N=32) shows:</p><ul><li><p><strong>Pure conduction with full-domain wall patch: PASSES</strong> (T error ≈ 0.012).</p></li><li><p><strong>Boussinesq natconv with full-domain wall patches: DIVERGES</strong> to NaN after ~2500–3500 sub-cycled steps on both N=24 and N=32.</p></li><li><p><strong>.krk dispatch (full-domain patches)</strong>: stable but Nu ≈ 1.87 vs Fusegi reference 1.085 (~72% over-prediction).</p></li></ul><p>Root cause: the FH f_neq interaction with Boussinesq coupling at the domain-boundary rows of 3D patches creates a feedback loop that 2D does not exhibit (D2Q9 has only 9 pops and 4-point bilinear stencil, while D3Q19 has 19 pops and 8-point trilinear stencil with 5 boundary faces).</p><p>Workaround for v0.1.0: use <strong>partial-domain 3D thermal patches</strong> (2–3-cell margin from non-thermal walls). Ongoing investigation tracked as a v0.2.0 follow-up.</p><p>2D full-domain wall patches work without issue (Nu err ~1.4%).</p><h2 id="5.-Geometry-and-obstacles" tabindex="-1">5. Geometry and obstacles <a class="header-anchor" href="#5.-Geometry-and-obstacles" aria-label="Permalink to &quot;5. Geometry and obstacles {#5.-Geometry-and-obstacles}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">Status</th><th style="text-align:right;">.krk syntax</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Implicit condition (circle, box, sphere)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Obstacle cyl { (x-cx)^2 + (y-cy)^2 &lt;= R^2 }</code></td><td style="text-align:right;">any boolean expression</td></tr><tr><td style="text-align:right;">STL import (binary + ASCII)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Obstacle body stl(file=&quot;geom.stl&quot;, scale=0.5)</code></td><td style="text-align:right;">auto-detect format</td></tr><tr><td style="text-align:right;">3D voxelization (Möller–Trumbore ray casting)</td><td style="text-align:center;">✓</td><td style="text-align:right;">—</td><td style="text-align:right;">requires watertight mesh</td></tr><tr><td style="text-align:right;">2D voxelization (slice at z_slice)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>stl(file=..., z_slice=0.0)</code></td><td style="text-align:right;">—</td></tr><tr><td style="text-align:right;">Named primitives <code>circle()</code>, <code>box()</code>, <code>sphere()</code></td><td style="text-align:center;">✗</td><td style="text-align:right;">planned v0.2.0</td><td style="text-align:right;">ergonomic sugar for common shapes</td></tr><tr><td style="text-align:right;">Multiple obstacles</td><td style="text-align:center;">✓</td><td style="text-align:right;">repeat <code>Obstacle</code> block</td><td style="text-align:right;">—</td></tr><tr><td style="text-align:right;">Fluid region (inverse logic)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Fluid inside { x &lt; L/2 }</code></td><td style="text-align:right;">—</td></tr></tbody></table><ul><li><p>Theory: — (voxelization is implementation detail, not LBM theory)</p></li><li><p>API: <a href="./api/io">io</a> — <code>read_stl</code>, <code>voxelize_2d</code>, <code>voxelize_3d</code></p></li></ul><p><strong>Limitation:</strong> no named primitives yet. Users must spell out <code>(x-cx)^2 + (y-cy)^2 &lt;= R^2</code>. Planned for v0.2.0:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Obstacle cyl circle(center=[0.5, 0.5], radius=0.1)</span></span>
<span class="line"><span>Obstacle box rectangle(xmin=0.2, xmax=0.8, ymin=0.3, ymax=0.7)</span></span>
<span class="line"><span>Obstacle sph sphere(center=[0.5, 0.5, 0.5], radius=0.1)</span></span></code></pre></div><h2 id="6.-Sanity-checks-parameter-validation" tabindex="-1">6. Sanity checks (parameter validation) <a class="header-anchor" href="#6.-Sanity-checks-parameter-validation" aria-label="Permalink to &quot;6. Sanity checks (parameter validation) {#6.-Sanity-checks-parameter-validation}&quot;">​</a></h2><p>Running <code>sanity_check(setup)</code> — and the check that <code>run_simulation</code> does automatically — covers the following:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Check</th><th style="text-align:right;">Level</th><th style="text-align:right;">What it verifies</th></tr></thead><tbody><tr><td style="text-align:right;">Relaxation τ = 3ν + 0.5</td><td style="text-align:right;">error/warn</td><td style="text-align:right;">τ &lt; 0.5 unstable; τ &lt; 0.51 marginal; τ &gt; 10 over-diffusive</td></tr><tr><td style="text-align:right;">Compressibility</td><td style="text-align:right;">error/warn</td><td style="text-align:right;">U_ref (Ma = U/c_s); Ma &gt; 0.1 flags compressibility error</td></tr><tr><td style="text-align:right;">Spatial resolution</td><td style="text-align:right;">warn</td><td style="text-align:right;">N &lt; 10, N/Re &lt; 1 (boundary layer under-resolved)</td></tr><tr><td style="text-align:right;">Thermal τ_α = 3α + 0.5</td><td style="text-align:right;">error/warn</td><td style="text-align:right;">same bounds as flow τ</td></tr><tr><td style="text-align:right;">Prandtl number</td><td style="text-align:right;">warn</td><td style="text-align:right;">Pr &lt; 0.1 or &gt; 10 extreme for SRT thermal</td></tr><tr><td style="text-align:right;">Rheology τ_min</td><td style="text-align:right;">warn</td><td style="text-align:right;">from <code>nu_min</code> in GNF models</td></tr><tr><td style="text-align:right;"><strong>Fine-grid τ (refinement)</strong></td><td style="text-align:right;">warn</td><td style="text-align:right;">Filippova-Hanel rescaled τ on each patch</td></tr><tr><td style="text-align:right;"><strong>Fine-grid τ_α (refinement)</strong></td><td style="text-align:right;">warn</td><td style="text-align:right;">thermal τ on fine grids (added in 3f05d79)</td></tr><tr><td style="text-align:right;"><strong>Fine-grid N/Re</strong></td><td style="text-align:right;">warn</td><td style="text-align:right;">boundary layer resolution on refined patch</td></tr><tr><td style="text-align:right;">Two-phase density/viscosity ratio</td><td style="text-align:right;">warn</td><td style="text-align:right;">code present, v0.2.0</td></tr></tbody></table><ul><li><p>.krk: <a href="./krk/sanity">Sanity checks</a></p></li><li><p>Parameter summary is printed at run-time with 2D/3D tag.</p></li></ul><p><strong>Limitations / planned:</strong></p><ul><li><p>No Ra-vs-N thermal BL resolution check (planned — ~ Ra^{1/4} minimum N).</p></li><li><p>No CFL check for prescribed-velocity advection (VOF is v0.2.0 anyway).</p></li><li><p>Custom user checks not yet exposed in .krk.</p></li></ul><h2 id="7.-KRK-DSL" tabindex="-1">7. KRK DSL <a class="header-anchor" href="#7.-KRK-DSL" aria-label="Permalink to &quot;7. KRK DSL {#7.-KRK-DSL}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Feature</th><th style="text-align:center;">Status</th><th style="text-align:right;">Reference</th></tr></thead><tbody><tr><td style="text-align:right;"><code>.krk</code> extension + VSCode highlighting</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/overview">overview</a></td></tr><tr><td style="text-align:right;">Core directives (Simulation, Domain, Physics, Run, Output)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/directives">directives</a></td></tr><tr><td style="text-align:right;">Boundary / Initial / Obstacle / Fluid / Velocity blocks</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/directives">directives</a></td></tr><tr><td style="text-align:right;">Modules: <code>thermal</code>, <code>axisymmetric</code></td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/modules">modules</a></td></tr><tr><td style="text-align:right;">Rheology block (GNF + VE parsing)</td><td style="text-align:center;">✓</td><td style="text-align:right;">code present, v0.2.0 scope</td></tr><tr><td style="text-align:right;">Refine block (2D and 3D)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/directives">directives</a></td></tr><tr><td style="text-align:right;">Define user variables</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/expressions">expressions</a></td></tr><tr><td style="text-align:right;">Expressions (math + <code>x, y, z, t</code>)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/expressions">expressions</a></td></tr><tr><td style="text-align:right;"><strong>Greek letters</strong> (ν/nu, ρ/rho, σ/sigma, τ/tau …)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/aliases">aliases</a></td></tr><tr><td style="text-align:right;">ASCII aliases (<code>nu</code> → <code>ν</code>)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/aliases">aliases</a></td></tr><tr><td style="text-align:right;"><strong>CLI wrapper</strong> (<code>krk sim.krk</code>)</td><td style="text-align:center;">✓</td><td style="text-align:right;">installed bin: <code>bin/krk</code></td></tr><tr><td style="text-align:right;">Preset templates (cavity_2d, etc.)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/presets">presets</a></td></tr><tr><td style="text-align:right;">Setup helpers (<code>Setup reynolds = 100</code>)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/helpers">helpers</a></td></tr><tr><td style="text-align:right;">Sweep (parametric studies)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><a href="./krk/directives">directives</a></td></tr></tbody></table><p><strong>Limitations:</strong></p><ul><li><p>No <code>include</code> directive for reusable .krk fragments.</p></li><li><p>No conditional blocks (<code>if Re &gt; 100 { ... }</code>).</p></li><li><p>Sweeps are Cartesian product; no Latin hypercube.</p></li></ul><h2 id="8.-GPU-support" tabindex="-1">8. GPU support <a class="header-anchor" href="#8.-GPU-support" aria-label="Permalink to &quot;8. GPU support {#8.-GPU-support}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Backend</th><th style="text-align:center;">Status</th><th style="text-align:right;">File type</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">CPU (KernelAbstractions)</td><td style="text-align:center;">✓</td><td style="text-align:right;">Float32/Float64</td><td style="text-align:right;">reference</td></tr><tr><td style="text-align:right;">Metal (Apple Silicon)</td><td style="text-align:center;">✓</td><td style="text-align:right;">Float32 recommended</td><td style="text-align:right;">M3 Max validated</td></tr><tr><td style="text-align:right;">CUDA (NVIDIA)</td><td style="text-align:center;">✓</td><td style="text-align:right;">Float32/Float64</td><td style="text-align:right;">H100 + A100 validated</td></tr><tr><td style="text-align:right;">ROCm (AMD)</td><td style="text-align:center;">✗</td><td style="text-align:right;">—</td><td style="text-align:right;">KA supports it, not tested</td></tr><tr><td style="text-align:right;">oneAPI (Intel)</td><td style="text-align:center;">✗</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td></tr></tbody></table><ul><li><p>All kernels use <code>KernelAbstractions.@kernel</code> → single source, multi-backend.</p></li><li><p><strong>Fix a82957c:</strong> <code>unsafe_trunc</code> instead of <code>trunc(Int, ...)</code> in all refinement and dualgrid kernels (required for Metal; allocated on GPU).</p></li></ul><p><strong>Performance reference (H100):</strong> 7675 MLUPS BGK D2Q9 at N=1024, 24k MLUPS with AA+Float32 kernels (see <a href="./benchmarks/mlups_cpu_gpu">MLUPS CPU vs GPU</a>).</p><h2 id="9.-Rheology-v0.2.0-scope" tabindex="-1">9. Rheology (v0.2.0 scope) <a class="header-anchor" href="#9.-Rheology-v0.2.0-scope" aria-label="Permalink to &quot;9. Rheology (v0.2.0 scope) {#9.-Rheology-v0.2.0-scope}&quot;">​</a></h2><p>The following are <strong>implemented in code and tested</strong> but excluded from v0.1.0 publication scope. They will be documented in v0.2.0.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Model</th><th style="text-align:center;">2D</th><th style="text-align:center;">3D</th><th style="text-align:center;">GPU</th><th style="text-align:center;">Thermal coupling</th></tr></thead><tbody><tr><td style="text-align:right;">Newtonian</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">Power-law</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">Carreau-Yasuda</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">Cross</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">Bingham (Papanastasiou)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">Herschel–Bulkley</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">Oldroyd-B (log-conf)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">FENE-P</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr><tr><td style="text-align:right;">Saramito (EVP)</td><td style="text-align:center;">✓</td><td style="text-align:center;">✗</td><td style="text-align:center;">✓</td><td style="text-align:center;">Arrhenius / WLF</td></tr></tbody></table><p>Effective viscosity dispatches at compile-time (zero-cost abstraction via Julia&#39;s JIT). See <code>src/rheology/</code> (models, viscosity, strain_rate).</p><h2 id="10.-Output-and-diagnostics" tabindex="-1">10. Output and diagnostics <a class="header-anchor" href="#10.-Output-and-diagnostics" aria-label="Permalink to &quot;10. Output and diagnostics {#10.-Output-and-diagnostics}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Output</th><th style="text-align:center;">Status</th><th style="text-align:right;">.krk syntax</th></tr></thead><tbody><tr><td style="text-align:right;">VTK (+ PVD time series)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Output vtk every 1000 [rho, ux, uy]</code></td></tr><tr><td style="text-align:right;">PNG snapshots (CairoMakie)</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Output png every 500 [uy]</code></td></tr><tr><td style="text-align:right;">GIF animations</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Output gif every 100 [ux] fps=15</code></td></tr><tr><td style="text-align:right;">Diagnostics CSV</td><td style="text-align:center;">✓</td><td style="text-align:right;"><code>Diagnostics every 100 [step, drag, lift]</code></td></tr><tr><td style="text-align:right;">ParaView-ready layout</td><td style="text-align:center;">✓</td><td style="text-align:right;">— (VTK pvd files)</td></tr></tbody></table><ul><li><p>API: <a href="./api/io">io</a>, <a href="./api/postprocess">postprocess</a></p></li><li><p>Helper: <code>open_paraview(result)</code> opens the latest output in ParaView.</p></li></ul><hr><h2 id="Out-of-scope-for-v0.1.0" tabindex="-1">Out-of-scope for v0.1.0 <a class="header-anchor" href="#Out-of-scope-for-v0.1.0" aria-label="Permalink to &quot;Out-of-scope for v0.1.0 {#Out-of-scope-for-v0.1.0}&quot;">​</a></h2><p>These features exist in the codebase (tests often pass) but are deliberately not documented in v0.1.0:</p><ul><li><p><strong>Multiphase (VOF + PLIC)</strong> — see <code>src/kernels/vof_2d.jl</code>, <code>src/kernels/pressure_vof_2d.jl</code> · v0.2.0</p></li><li><p><strong>Phase-field (Allen-Cahn)</strong> — <code>src/kernels/phasefield_2d.jl</code> · v0.2.0</p></li><li><p><strong>Shan–Chen spinodal</strong> — <code>src/drivers/multiphase.jl</code> · v0.2.0</p></li><li><p><strong>Species transport</strong> — <code>src/kernels/species_2d.jl</code> · v0.2.0</p></li><li><p><strong>Viscoelastic cylinder</strong> — <code>src/drivers/viscoelastic.jl</code> · v0.2.0</p></li><li><p><strong>3D rheology</strong> — kernels 2D only · v0.2.0 or later</p></li><li><p><strong>3D MRT</strong> — D3Q19 BGK only · v0.2.0 or later</p></li></ul><hr><h2 id="Quick-decision-helper" tabindex="-1">Quick decision helper <a class="header-anchor" href="#Quick-decision-helper" aria-label="Permalink to &quot;Quick decision helper {#Quick-decision-helper}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">I want to…</th><th style="text-align:right;">I need…</th></tr></thead><tbody><tr><td style="text-align:right;">lid-driven cavity 2D</td><td style="text-align:right;">BGK + wall BCs + velocity BC. <a href="./examples/04_cavity_2d">Example</a></td></tr><tr><td style="text-align:right;">flow past a cylinder</td><td style="text-align:right;">BGK + inlet parabolic BC + obstacle (<code>Obstacle { ... }</code>). <a href="./examples/06_cylinder_2d">Example</a></td></tr><tr><td style="text-align:right;">natural convection in a cavity</td><td style="text-align:right;"><code>Module thermal</code> + two <code>wall(T=...)</code> BCs. <a href="./examples/08_rayleigh_benard">Example</a></td></tr><tr><td style="text-align:right;">refine near a wall</td><td style="text-align:right;">add <code>Refine name { region=[...], ratio=2 }</code> block. <a href="./examples/20_grid_refinement_cavity">20</a></td></tr><tr><td style="text-align:right;">run on H100/A100</td><td style="text-align:right;"><code>backend = CUDABackend(); run_simulation(...; backend=backend)</code></td></tr><tr><td style="text-align:right;">vary the viscosity with temperature</td><td style="text-align:right;">call <code>run_natural_convection_2d(; Rc=10)</code> directly (not via .krk yet)</td></tr><tr><td style="text-align:right;">use an STL geometry</td><td style="text-align:right;"><code>Obstacle body stl(file=&quot;geom.stl&quot;)</code></td></tr><tr><td style="text-align:right;">sweep parameters</td><td style="text-align:right;"><code>Sweep Re = [100, 200, 400]</code></td></tr><tr><td style="text-align:right;">run from the terminal</td><td style="text-align:right;"><code>krk sim.krk</code> (CLI wrapper)</td></tr></tbody></table>`,58)])])}const x=e(a,[["render",n]]);export{h as __pageData,x as default};
